const s = $('Query Stats').first().json;
const recent = $('Last 10 Processed').all().map(i => i.json);
const failures = $('Failed Companies').all().map(i => i.json);

// Proxy stats
let proxyLines = [];
try {
  const px = $('Proxy Pool Stats').all();
  if (px.length > 0) {
    proxyLines = px.map(p => `${p.json.status}: ${p.json.cnt} proxies (avg ${p.json.avg_ms || '?'}ms)`);
  }
} catch(e) { proxyLines = ['Tabla proxies no disponible']; }

// Per-batch stats
let batchLines = [];
try {
  const batches = $('Per-Batch Stats').all();
  if (batches.length > 0) {
    batchLines = batches.map(b => {
      const j = b.json;
      const pct = j.total > 0 ? ((j.enriched / j.total) * 100).toFixed(1) : '0';
      return `Batch ${j.batch}: ${j.enriched}/${j.total} enriched (${pct}%) | ${j.failing} failed | ${j.not_found} not_found`;
    });
  }
} catch(e) { batchLines = ['Sin datos de batch (batch_number no asignado)']; }

const total = parseInt(s.total) || 0;
const enriched = parseInt(s.enriched) || 0;
const failed = parseInt(s.failed) || 0;
const failedRetry = parseInt(s.failed_retry) || 0;
const notFound = parseInt(s.not_found) || 0;
const fixedByRetry = parseInt(s.fixed_by_retry) || 0;
const TARGET = 872051;

const t1 = parseInt(s.tier1) || 0;
const t2 = parseInt(s.tier2) || 0;
const t3 = parseInt(s.tier3) || 0;
const t4 = parseInt(s.tier4) || 0;
const t5 = parseInt(s.tier5) || 0;

const errProxy = parseInt(s.err_proxy) || 0;
const errParse = parseInt(s.err_parse) || 0;
const errNotFound = parseInt(s.err_not_found) || 0;

const avgSec = s.avg_sec || 'N/A';
const remaining = TARGET - total;
const processingRate = parseFloat(avgSec || 5) + 15; // avg scrape + 15s wait
const etaHours = remaining > 0 ? Math.round(remaining * processingRate / 3600) : 0;
const etaDays = remaining > 0 ? (etaHours / 24).toFixed(1) : '0';

const processed = total - notFound; // excludes not_found for success rate
const successRate = processed > 0 ? ((enriched / processed) * 100).toFixed(1) : '0';
const totalErrors = failed + failedRetry;

return { json: {
  report: [
    '══════════════════════════════════════════════════',
    '  EMPLIQ PIPELINE MONITOR v2.1',
    '  Target: 872,051 empresas (Padrón RUC completo)',
    '  Arquitectura: 10 batches × ~87K | Retry cada 2h',
    '══════════════════════════════════════════════════',
    '',
    `🎯 PROGRESO GLOBAL: ${total.toLocaleString()} / ${TARGET.toLocaleString()} (${((total/TARGET)*100).toFixed(2)}%)`,
    `   Pendientes: ${remaining.toLocaleString()} | ETA: ~${etaHours}h (~${etaDays} días)`,
    '',
    '── RESULTADOS ──────────────────────────────────',
    `   ✅ Enriched:        ${enriched.toLocaleString()}`,
    `   🚫 Not Found:       ${notFound.toLocaleString()} (permanente, no se reintenta)`,
    `   ❌ Failed:          ${failed.toLocaleString()} (primer intento)`,
    `   ❌ Failed Retry:    ${failedRetry.toLocaleString()} (reintento fallido)`,
    `   🔄 Fixed by Retry:  ${fixedByRetry.toLocaleString()} (recuperados)`,
    `   📊 Success Rate:    ${successRate}% (excluyendo not_found)`,
    '',
    '── POR TIER ────────────────────────────────────',
    `   Tier 1 (≥1000 emp):  ${t1.toLocaleString()}`,
    `   Tier 2 (500-999):    ${t2.toLocaleString()}`,
    `   Tier 3 (100-499):    ${t3.toLocaleString()}`,
    `   Tier 4 (50-99):      ${t4.toLocaleString()}`,
    `   Tier 5 (0-49):       ${t5.toLocaleString()}`,
    '',
    '── ERRORES (tipo) ──────────────────────────────',
    `   🔌 Proxy Error:  ${errProxy} (proxy caído/blacklisted)`,
    `   📄 Parse Error:  ${errParse} (HTML inesperado)`,
    `   🔍 Not Found:    ${errNotFound} (empresa no existe en DatosPeru)`,
    '',
    '── PROXIES (tabla proxies) ────────────────────',
    ...proxyLines.map(l => `   ${l}`),
    '',
    '── POR BATCH (/files/all_padron_batch_XX.csv) ─',
    ...batchLines.map(l => `   ${l}`),
    '',
    '── TIMING ──────────────────────────────────────',
    `   Avg scrape:   ${avgSec}s`,
    `   Avg fields:   ${s.avg_fields || 'N/A'}`,
    `   Wait/item:    15s`,
    `   Rate:         ~${Math.round(3600 / processingRate)}/hora`,
    `   Started:      ${s.started_at || 'N/A'}`,
    `   Last update:  ${s.last_updated || 'N/A'}`,
    '',
    '── WORKFLOWS ACTIVOS ──────────────────────────',
    '   📦 Enrichment Batch XX/10  (secuencial, 1 activo a la vez)',
    '   🔄 Retry Failed Companies  (cada 2h, failed + failed_retry)',
    '   🔍 Proxy Discover          (cada 6h, fuentes SOCKS5)',
    '   ✅ Proxy Validate           (cada 30min, POST /proxies/test)',
    '   🖼️ Logo Pipeline            (logos DatosPeru → Oracle Storage)',
    '',
    '── LAST 10 PROCESSED ──────────────────────────',
    ...recent.map(r => `   ${r.ruc} | ${(r.razon_social||'').substring(0,30).padEnd(30)} | ${(r.status||'').padEnd(20)} | ${r.fields||0} flds | ${r.tier} | ${r.error_type||'ok'}`),
    '',
    '── TOP 20 FAILURES ────────────────────────────',
    `   Total errores activos: ${totalErrors}`,
    ...failures.map(f => `   ${f.ruc} | ${(f.razon_social||'').substring(0,25)} | [${f.error_type||'?'}] ${(f.error||'no detail').substring(0,45)}`)
  ].join('\n')
}};
